{
  "title": "Thai Cooking for Beginners",
  "description": "This course is designed for beginners who are eager to learn the essentials of Thai cuisine. Participants will explore fundamental cooking techniques, key ingredients, and traditional recipes to enhance their culinary skills and confidence in the kitchen.",
  "modules": [
    {
      "id": "module1",
      "title": "Introduction to Thai Cuisine",
      "description": "Explore the history, culture, and key ingredients of Thai cuisine. Learn about essential herbs and spices that define Thai flavors, and how to source them."
    },
    {
      "id": "module2",
      "title": "Basic Cooking Techniques",
      "description": "Learn fundamental cooking techniques used in Thai cooking, including stir-frying, steaming, and making curry pastes. Hands-on practice with essential kitchen tools."
    },
    {
      "id": "module3",
      "title": "Signature Thai Dishes",
      "description": "Prepare classic Thai dishes such as Pad Thai, Tom Yum Soup, and Green Curry. Understand the balance of flavors and presentation in Thai cooking."
    },
    {
      "id": "module4",
      "title": "Creating Your Own Thai Meals",
      "description": "Combine your skills to create personalized Thai meals. Learn how to adjust recipes to taste and incorporate seasonal ingredients for everyday cooking."
    }
  ]
}
